-- =============================================================================
-- PARKING BUILDING MANAGEMENT SYSTEM
-- PostgreSQL Database Schema - HOÀN CHỈNH & ĐÃ FIX
-- Version: 4.0 FINAL
-- Project: SU26SWP08 - Hệ thống quản lý tòa nhà gửi xe
-- Architecture: Dual Backend (ASP.NET Core + Spring Boot) shared PostgreSQL
-- =============================================================================
-- FIX LOG:
--   [F01] Chuyển tất cả ENUM sang VARCHAR(30) + CHECK để EF Core & Hibernate dễ map
--   [F02] Đổi BIGSERIAL sang BIGINT GENERATED BY DEFAULT AS IDENTITY
--   [F03] Thêm SET timezone TO 'Asia/Ho_Chi_Minh' đầu file
--   [F04] Thêm bảng vehicle_types (thay thế ENUM vehicle_type_enum)
--   [F05] Thêm bảng area_vehicle_types (thay TEXT[] trong parking_areas)
--   [F06] Thêm bảng system_configs (Spec 8.22)
--   [F07] Đổi tên bảng: rfid_cards->parking_cards, parking_floors->floors,
--         parking_areas->areas, parking_slots->slots, price_rules->pricing_rules,
--         payment_transactions->payments, resident_subscriptions->monthly_passes
--   [F08] parking_sessions: thêm no_plate , vehicle_description, payment_required,
--         suggestion cols, snapshot cols phẳng, đổi cancel_reason->cancellation_reason
--   [F09] users: thêm phone (alias), status varchar
--   [F10] driver_profiles: thêm phone, email, status
--   [F11] monthly_passes: redesign theo Spec 8.15 (phẳng, giảm phụ thuộc)
--   [F12] parking_cards: thêm current_session_id
--   [F13] slots: thêm allowed_vehicle_type_id, current_session_id
--   [F14] reservations: đổi slot_id -> original_spot_id + assigned_spot_id
--   [F15] payments: thêm waive_reason
--   [F16] Trigger fn_check_reservation_car_b2: sửa hardcode 'B2' -> management_type
--   [F17] Trigger fn_update_area_occupancy: bổ sung logic UPDATE area_id
--   [F18] MV: UNIQUE INDEX tạo trước REFRESH CONCURRENTLY
--   [F19] Seed data: đổi username sang admin01/manager01/staff01/driver01
--   [F20] Seed vehicle_types đầy đủ
--   [F21] Giữ backward-compat views cho tên bảng cũ
-- =============================================================================

-- [F03] Khóa cứng múi giờ
SET timezone TO 'Asia/Ho_Chi_Minh';

-- =============================================================================
-- SAFE RESET
-- =============================================================================
DROP SCHEMA IF EXISTS public CASCADE;
CREATE SCHEMA public;
SET timezone TO 'Asia/Ho_Chi_Minh';

-- =============================================================================
-- SECTION 0: EXTENSIONS
-- =============================================================================
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pg_trgm";
CREATE EXTENSION IF NOT EXISTS "btree_gin";

-- =============================================================================
-- SHARED TRIGGER FUNCTION
-- =============================================================================
CREATE OR REPLACE FUNCTION fn_set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- =============================================================================
-- SECTION 1: CORE USER & AUTH TABLES
-- [F01] Dùng VARCHAR+CHECK thay ENUM
-- [F02] BIGINT GENERATED BY DEFAULT AS IDENTITY thay BIGSERIAL
-- =============================================================================

CREATE TABLE users (
    id                  BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    username            VARCHAR(100)    NOT NULL,
    email               VARCHAR(255)    NOT NULL,
    password_hash       VARCHAR(512)    NULL,
    role                VARCHAR(30)     NOT NULL,
    status              VARCHAR(30)     NOT NULL DEFAULT 'ACTIVE',
    account_status      VARCHAR(30)     NOT NULL DEFAULT 'ACTIVE',
    auth_provider       VARCHAR(20)     NOT NULL DEFAULT 'LOCAL',
    oauth_provider_id   VARCHAR(255)    NULL,
    full_name           VARCHAR(255)    NOT NULL,
    phone               VARCHAR(20)     NULL,
    phone_number        VARCHAR(20)     NULL,
    avatar_url          VARCHAR(500)    NULL,
    last_login_at       TIMESTAMPTZ     NULL,
    login_failed_count  INT             NOT NULL DEFAULT 0,
    locked_until        TIMESTAMPTZ     NULL,
    email_verified      BOOLEAN         NOT NULL DEFAULT FALSE,
    created_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    created_by          BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    is_deleted          BOOLEAN         NOT NULL DEFAULT FALSE,
    deleted_at          TIMESTAMPTZ     NULL,
    deleted_by          BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    version             INT             NOT NULL DEFAULT 0,

    CONSTRAINT uq_users_email       UNIQUE (email),
    CONSTRAINT uq_users_username    UNIQUE (username),
    CONSTRAINT uq_users_oauth       UNIQUE (auth_provider, oauth_provider_id),
    CONSTRAINT chk_users_role
        CHECK (role IN ('ADMIN','MANAGER','STAFF','DRIVER')),
    CONSTRAINT chk_users_account_status
        CHECK (account_status IN ('ACTIVE','INACTIVE','SUSPENDED','PENDING_VERIFICATION')),
    CONSTRAINT chk_users_status
        CHECK (status IN ('ACTIVE','INACTIVE','SUSPENDED','PENDING_VERIFICATION')),
    CONSTRAINT chk_users_auth_provider
        CHECK (auth_provider IN ('LOCAL','GOOGLE','FACEBOOK')),
    CONSTRAINT chk_users_local_has_password
        CHECK (
            (auth_provider = 'LOCAL' AND password_hash IS NOT NULL)
            OR auth_provider IN ('GOOGLE','FACEBOOK')
        ),
    CONSTRAINT chk_users_oauth_has_id
        CHECK (
            (auth_provider IN ('GOOGLE','FACEBOOK') AND oauth_provider_id IS NOT NULL)
            OR auth_provider = 'LOCAL'
        ),
    CONSTRAINT chk_users_internal_role_local_only
        CHECK (
            (role IN ('ADMIN','MANAGER','STAFF') AND auth_provider = 'LOCAL')
            OR role = 'DRIVER'
        )
);

COMMENT ON TABLE users IS 'Tài khoản hệ thống. phone/status là alias cho phone_number/account_status.';
COMMENT ON COLUMN users.version IS 'Optimistic locking cho .NET & Spring Boot';

-- Trigger sync alias fields
CREATE OR REPLACE FUNCTION fn_users_sync_aliases()
RETURNS TRIGGER AS $$
BEGIN
    -- Sync phone <-> phone_number
    IF NEW.phone IS NOT NULL AND NEW.phone_number IS DISTINCT FROM NEW.phone THEN
        NEW.phone_number = NEW.phone;
    ELSIF NEW.phone_number IS NOT NULL AND NEW.phone IS DISTINCT FROM NEW.phone_number THEN
        NEW.phone = NEW.phone_number;
    END IF;
    -- Sync status <-> account_status
    IF NEW.status IS NOT NULL AND NEW.account_status IS DISTINCT FROM NEW.status THEN
        NEW.account_status = NEW.status;
    ELSIF NEW.account_status IS NOT NULL AND NEW.status IS DISTINCT FROM NEW.account_status THEN
        NEW.status = NEW.account_status;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_users_sync_aliases
    BEFORE INSERT OR UPDATE ON users
    FOR EACH ROW EXECUTE FUNCTION fn_users_sync_aliases();

CREATE TRIGGER trg_users_updated_at
    BEFORE UPDATE ON users
    FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

CREATE INDEX idx_users_email          ON users (email)           WHERE is_deleted = FALSE;
CREATE INDEX idx_users_role           ON users (role)            WHERE is_deleted = FALSE;
CREATE INDEX idx_users_account_status ON users (account_status)  WHERE is_deleted = FALSE;
CREATE INDEX idx_users_oauth          ON users (auth_provider, oauth_provider_id)
    WHERE oauth_provider_id IS NOT NULL;
CREATE INDEX idx_users_phone          ON users (phone_number)    WHERE phone_number IS NOT NULL;

-- =============================================================================
-- SECTION 2: ROLES & PERMISSIONS (MF-01)
-- =============================================================================

CREATE TABLE roles (
    id          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    role_name   VARCHAR(50)     NOT NULL UNIQUE,
    description TEXT            NULL,
    is_active   BOOLEAN         NOT NULL DEFAULT TRUE,
    created_at  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ     NOT NULL DEFAULT NOW()
);
COMMENT ON TABLE roles IS 'Danh sách role hệ thống.';

CREATE TRIGGER trg_roles_updated_at
    BEFORE UPDATE ON roles FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

CREATE TABLE permissions (
    id              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    permission_code VARCHAR(100)    NOT NULL UNIQUE,
    permission_name VARCHAR(255)    NOT NULL,
    module          VARCHAR(50)     NOT NULL,
    description     TEXT            NULL,
    created_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW()
);
COMMENT ON TABLE permissions IS 'Quyền chi tiết hệ thống.';

CREATE INDEX idx_permissions_module ON permissions (module);

CREATE TABLE role_permissions (
    id              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    role_id         BIGINT      NOT NULL REFERENCES roles(id) ON DELETE CASCADE,
    permission_id   BIGINT      NOT NULL REFERENCES permissions(id) ON DELETE CASCADE,
    granted_by      BIGINT      NULL REFERENCES users(id) ON DELETE SET NULL,
    granted_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_role_permission UNIQUE (role_id, permission_id)
);

CREATE INDEX idx_role_permissions_role_id       ON role_permissions (role_id);
CREATE INDEX idx_role_permissions_permission_id ON role_permissions (permission_id);

-- =============================================================================
-- SECTION 3: DRIVER PROFILES [F10]
-- =============================================================================

CREATE TABLE driver_profiles (
    id                      BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    user_id                 BIGINT          NOT NULL UNIQUE REFERENCES users(id) ON DELETE CASCADE,
    driver_type             VARCHAR(20)     NOT NULL DEFAULT 'VISITOR',
    phone                   VARCHAR(20)     NULL,
    email                   VARCHAR(255)    NULL,
    status                  VARCHAR(30)     NOT NULL DEFAULT 'ACTIVE',
    apartment_number        VARCHAR(20)     NULL,
    cccd_number             VARCHAR(20)     NULL,
    cccd_image_url          VARCHAR(500)    NULL,
    resident_verified       BOOLEAN         NOT NULL DEFAULT FALSE,
    resident_verified_at    TIMESTAMPTZ     NULL,
    resident_verified_by    BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    created_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_driver_type
        CHECK (driver_type IN ('RESIDENT','VISITOR')),
    CONSTRAINT chk_driver_status
        CHECK (status IN ('ACTIVE','INACTIVE','SUSPENDED')),
    CONSTRAINT chk_driver_resident_fields
        CHECK (
            driver_type != 'RESIDENT'
            OR (apartment_number IS NOT NULL AND cccd_number IS NOT NULL)
        )
);
COMMENT ON TABLE driver_profiles IS 'Thông tin bổ sung của Driver.';

CREATE INDEX idx_driver_profiles_user_id   ON driver_profiles (user_id);
CREATE INDEX idx_driver_profiles_type      ON driver_profiles (driver_type);
CREATE INDEX idx_driver_profiles_apartment ON driver_profiles (apartment_number)
    WHERE apartment_number IS NOT NULL;

CREATE TRIGGER trg_driver_profiles_updated_at
    BEFORE UPDATE ON driver_profiles FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- =============================================================================
-- SECTION 4: VEHICLE TYPES (Spec 8.3) [F04]
-- =============================================================================

CREATE TABLE vehicle_types (
    id          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    code        VARCHAR(30)     NOT NULL UNIQUE,
    name        VARCHAR(100)    NOT NULL,
    description TEXT            NULL,
    is_active   BOOLEAN         NOT NULL DEFAULT TRUE,
    created_at  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ     NOT NULL DEFAULT NOW()
);
COMMENT ON TABLE vehicle_types IS 'Loại phương tiện. Thay thế vehicle_type_enum.';

CREATE INDEX idx_vehicle_types_code   ON vehicle_types (code);
CREATE INDEX idx_vehicle_types_active ON vehicle_types (is_active);

CREATE TRIGGER trg_vehicle_types_updated_at
    BEFORE UPDATE ON vehicle_types FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- =============================================================================
-- SECTION 5: VEHICLES
-- =============================================================================

-- [F01] IMMUTABLE function cho expression index
CREATE OR REPLACE FUNCTION fn_normalize_plate(plate TEXT)
RETURNS TEXT AS $$
BEGIN
    RETURN UPPER(REGEXP_REPLACE(plate, '[^A-Z0-9]', '', 'gi'));
END;
$$ LANGUAGE plpgsql IMMUTABLE STRICT;

CREATE TABLE vehicles (
    id                  BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    owner_id            BIGINT          NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    vehicle_type_id     BIGINT          NOT NULL REFERENCES vehicle_types(id) ON DELETE RESTRICT,
    vehicle_type        VARCHAR(30)     NOT NULL,
    license_plate       VARCHAR(20)     NULL,
    plate_normalized    VARCHAR(20)     NULL,
    vehicle_color       VARCHAR(50)     NULL,
    vehicle_brand       VARCHAR(100)    NULL,
    vehicle_model       VARCHAR(100)    NULL,
    vehicle_image_url   VARCHAR(500)    NULL,
    is_active           BOOLEAN         NOT NULL DEFAULT TRUE,
    notes               TEXT            NULL,
    created_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT uq_vehicles_plate_active UNIQUE NULLS NOT DISTINCT (license_plate, is_active),
    CONSTRAINT chk_vehicles_type
        CHECK (vehicle_type IN ('MOTORBIKE','CAR','TRUCK','BICYCLE')),
    CONSTRAINT chk_vehicles_plate_required
        CHECK (vehicle_type = 'BICYCLE' OR license_plate IS NOT NULL)
);
COMMENT ON TABLE vehicles IS 'Phương tiện của Driver. Bicycle không bắt buộc biển số.';

CREATE OR REPLACE FUNCTION fn_vehicles_normalize_plate()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.license_plate IS NOT NULL THEN
        NEW.plate_normalized = fn_normalize_plate(NEW.license_plate);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_vehicles_normalize_plate
    BEFORE INSERT OR UPDATE ON vehicles
    FOR EACH ROW EXECUTE FUNCTION fn_vehicles_normalize_plate();

CREATE TRIGGER trg_vehicles_updated_at
    BEFORE UPDATE ON vehicles FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

CREATE INDEX idx_vehicles_owner_id   ON vehicles (owner_id);
CREATE INDEX idx_vehicles_plate      ON vehicles (plate_normalized) WHERE plate_normalized IS NOT NULL;
CREATE INDEX idx_vehicles_type       ON vehicles (vehicle_type);
CREATE INDEX idx_vehicles_active     ON vehicles (owner_id, is_active);
CREATE INDEX idx_vehicles_plate_trgm ON vehicles USING GIN (plate_normalized gin_trgm_ops)
    WHERE plate_normalized IS NOT NULL;

-- =============================================================================
-- SECTION 6: FACILITY TABLES
-- [F07] floors (was parking_floors), areas (was parking_areas), slots (was parking_slots)
-- =============================================================================

-- TABLE: floors
CREATE TABLE floors (
    id              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    floor_code      VARCHAR(10)     NOT NULL,
    floor_name      VARCHAR(100)    NOT NULL,
    floor_order     INT             NOT NULL,
    management_type VARCHAR(30)     NOT NULL,
    total_capacity  INT             NOT NULL,
    description     TEXT            NULL,
    is_active       BOOLEAN         NOT NULL DEFAULT TRUE,
    created_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT uq_floors_code      UNIQUE (floor_code),
    CONSTRAINT chk_floors_mgmt_type
        CHECK (management_type IN ('AREA_ONLY','AREA_AND_SLOT','CAPACITY_ONLY')),
    CONSTRAINT chk_floors_capacity CHECK (total_capacity > 0)
);
COMMENT ON TABLE floors IS 'Các tầng gửi xe. Tên cũ: parking_floors.';
COMMENT ON COLUMN floors.management_type IS 'AREA_ONLY=B1, AREA_AND_SLOT=B2, CAPACITY_ONLY=B3';

CREATE OR REPLACE VIEW parking_floors AS SELECT * FROM floors;

CREATE INDEX idx_floors_code   ON floors (floor_code);
CREATE INDEX idx_floors_active ON floors (is_active);

CREATE TRIGGER trg_floors_updated_at
    BEFORE UPDATE ON floors FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- TABLE: areas
CREATE TABLE areas (
    id                    BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    floor_id              BIGINT          NOT NULL REFERENCES floors(id) ON DELETE RESTRICT,
    area_code             VARCHAR(10)     NOT NULL,
    area_name             VARCHAR(100)    NULL,
    total_capacity        INT             NOT NULL,
    current_occupancy     INT             NOT NULL DEFAULT 0,
    status                VARCHAR(20)     NOT NULL DEFAULT 'ACTIVE',
    display_order         INT             NOT NULL DEFAULT 0,
    description           TEXT            NULL,
    created_at            TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at            TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT uq_areas_floor_code  UNIQUE (floor_id, area_code),
    CONSTRAINT chk_areas_status
        CHECK (status IN ('ACTIVE','MAINTENANCE','TEMP_LOCKED','INACTIVE')),
    CONSTRAINT chk_areas_capacity   CHECK (total_capacity > 0),
    CONSTRAINT chk_areas_occupancy  CHECK (current_occupancy >= 0 AND current_occupancy <= total_capacity)
);
COMMENT ON TABLE areas IS 'Khu vực đỗ xe theo tầng. Tên cũ: parking_areas.';
COMMENT ON COLUMN areas.current_occupancy IS 'Cache - cập nhật bởi trigger fn_update_area_occupancy';

CREATE OR REPLACE VIEW parking_areas AS SELECT * FROM areas;

CREATE INDEX idx_areas_floor_id   ON areas (floor_id);
CREATE INDEX idx_areas_status     ON areas (status);
CREATE INDEX idx_areas_floor_code ON areas (floor_id, area_code);

CREATE TRIGGER trg_areas_updated_at
    BEFORE UPDATE ON areas FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- TABLE: area_vehicle_types (Spec 8.8) [F05]
CREATE TABLE area_vehicle_types (
    id              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    area_id         BIGINT  NOT NULL REFERENCES areas(id) ON DELETE CASCADE,
    vehicle_type_id BIGINT  NOT NULL REFERENCES vehicle_types(id) ON DELETE CASCADE,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_area_vehicle_type UNIQUE (area_id, vehicle_type_id)
);
COMMENT ON TABLE area_vehicle_types IS 'Loại xe được phép vào từng khu. Thay TEXT[] allowed_vehicle_types.';

CREATE INDEX idx_area_vt_area  ON area_vehicle_types (area_id);
CREATE INDEX idx_area_vt_vtype ON area_vehicle_types (vehicle_type_id);

-- TABLE: slots
CREATE TABLE slots (
    id                      BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    area_id                 BIGINT          NOT NULL REFERENCES areas(id) ON DELETE RESTRICT,
    slot_code               VARCHAR(10)     NOT NULL,
    slot_number             INT             NOT NULL,
    status                  VARCHAR(30)     NOT NULL DEFAULT 'AVAILABLE',
    allowed_vehicle_type_id BIGINT          NULL REFERENCES vehicle_types(id) ON DELETE SET NULL,
    current_session_id      BIGINT          NULL,   -- FK thêm sau
    is_premium              BOOLEAN         NOT NULL DEFAULT FALSE,
    notes                   TEXT            NULL,
    locked_by               BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    locked_at               TIMESTAMPTZ     NULL,
    locked_reason           TEXT            NULL,
    created_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    version                 INT             NOT NULL DEFAULT 0,

    CONSTRAINT uq_slots_area_code   UNIQUE (area_id, slot_code),
    CONSTRAINT uq_slots_area_number UNIQUE (area_id, slot_number),
    CONSTRAINT chk_slots_status
        CHECK (status IN (
            'AVAILABLE','RESERVED','OCCUPIED','MAINTENANCE',
            'TEMP_LOCKED','WRONG_OCCUPIED','DATA_CONFLICT'
        ))
);
COMMENT ON TABLE slots IS 'Slot đỗ cụ thể B2. Tên cũ: parking_slots.';

CREATE OR REPLACE VIEW parking_slots AS SELECT * FROM slots;

CREATE INDEX idx_slots_area_id     ON slots (area_id);
CREATE INDEX idx_slots_status      ON slots (status);
CREATE INDEX idx_slots_area_status ON slots (area_id, status);

CREATE TRIGGER trg_slots_updated_at
    BEFORE UPDATE ON slots FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- TABLE: gates
CREATE TABLE gates (
    id          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    floor_id    BIGINT          NOT NULL REFERENCES floors(id) ON DELETE RESTRICT,
    gate_code   VARCHAR(20)     NOT NULL,
    gate_name   VARCHAR(100)    NOT NULL,
    gate_type   VARCHAR(20)     NOT NULL,
    gate_status VARCHAR(20)     NOT NULL DEFAULT 'ACTIVE',
    description TEXT            NULL,
    created_at  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT uq_gates_floor_code  UNIQUE (floor_id, gate_code),
    CONSTRAINT chk_gates_type       CHECK (gate_type IN ('ENTRY','EXIT','BIDIRECTIONAL')),
    CONSTRAINT chk_gates_status     CHECK (gate_status IN ('ACTIVE','INACTIVE','MAINTENANCE'))
);
COMMENT ON TABLE gates IS 'Cổng vào/ra của từng tầng.';

CREATE INDEX idx_gates_floor_id ON gates (floor_id);
CREATE INDEX idx_gates_type     ON gates (gate_type);
CREATE INDEX idx_gates_status   ON gates (gate_status);

CREATE TRIGGER trg_gates_updated_at
    BEFORE UPDATE ON gates FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- =============================================================================
-- SECTION 7: PARKING CARDS (was rfid_cards) [F07][F12]
-- =============================================================================

CREATE TABLE parking_cards (
    id                  BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    card_code           VARCHAR(50)     NOT NULL,
    qr_token            UUID            NOT NULL DEFAULT gen_random_uuid(),
    card_status         VARCHAR(20)     NOT NULL DEFAULT 'AVAILABLE',
    assigned_to_user_id BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    current_session_id  BIGINT          NULL,   -- FK thêm sau khi có parking_sessions
    notes               TEXT            NULL,
    issued_at           TIMESTAMPTZ     NULL,
    last_used_at        TIMESTAMPTZ     NULL,
    created_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    version             INT             NOT NULL DEFAULT 0,

    CONSTRAINT uq_parking_cards_code      UNIQUE (card_code),
    CONSTRAINT uq_parking_cards_qr_token  UNIQUE (qr_token),
    CONSTRAINT chk_parking_cards_status
        CHECK (card_status IN ('AVAILABLE','IN_USE','LOST','DAMAGED','RESERVED','INACTIVE'))
);
COMMENT ON TABLE parking_cards IS 'Thẻ RFID vật lý. Tên cũ: rfid_cards. qr_token là UUID native (không ép TEXT).';

CREATE OR REPLACE VIEW rfid_cards AS SELECT * FROM parking_cards;

CREATE INDEX idx_parking_cards_code          ON parking_cards (card_code);
CREATE INDEX idx_parking_cards_status        ON parking_cards (card_status);
CREATE INDEX idx_parking_cards_assigned_user ON parking_cards (assigned_to_user_id)
    WHERE assigned_to_user_id IS NOT NULL;
CREATE INDEX idx_parking_cards_qr_token      ON parking_cards (qr_token);

CREATE TRIGGER trg_parking_cards_updated_at
    BEFORE UPDATE ON parking_cards FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- =============================================================================
-- SECTION 8: PRICING TABLES
-- [F07] pricing_rules (was price_rules)
-- =============================================================================

CREATE TABLE price_tables (
    id              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    table_name      VARCHAR(100)    NOT NULL,
    description     TEXT            NULL,
    is_active       BOOLEAN         NOT NULL DEFAULT TRUE,
    effective_from  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    effective_to    TIMESTAMPTZ     NULL,
    created_by      BIGINT          NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    created_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_price_tables_effective
        CHECK (effective_to IS NULL OR effective_to > effective_from)
);
COMMENT ON TABLE price_tables IS 'Bảng giá master. Chỉ Admin tạo.';

CREATE INDEX idx_price_tables_active    ON price_tables (is_active, effective_from);
CREATE INDEX idx_price_tables_effective ON price_tables (effective_from, effective_to);

CREATE TRIGGER trg_price_tables_updated_at
    BEFORE UPDATE ON price_tables FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- TABLE: pricing_rules (was price_rules) [F07]
-- Thiết kế phẳng theo Spec 8.12 - logic block do .NET FeeCalculationService xử lý
CREATE TABLE pricing_rules (
    id              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    price_table_id  BIGINT          NOT NULL REFERENCES price_tables(id) ON DELETE CASCADE,
    vehicle_type    VARCHAR(30)     NOT NULL,
    customer_type   VARCHAR(20)     NOT NULL,
    day_price       NUMERIC(12,2)   NOT NULL DEFAULT 0,
    night_price     NUMERIC(12,2)   NOT NULL DEFAULT 0,
    monthly_price   NUMERIC(12,2)   NOT NULL DEFAULT 0,
    lost_card_fee   NUMERIC(12,2)   NOT NULL DEFAULT 150000,
    free_minutes    INT             NOT NULL DEFAULT 15,
    block_minutes   INT             NOT NULL DEFAULT 240,
    day_start_hour  INT             NOT NULL DEFAULT 6,
    day_end_hour    INT             NOT NULL DEFAULT 18,
    is_active       BOOLEAN         NOT NULL DEFAULT TRUE,
    notes           TEXT            NULL,

    CONSTRAINT uq_pricing_rules_combo UNIQUE (price_table_id, vehicle_type, customer_type),
    CONSTRAINT chk_pricing_rules_vtype
        CHECK (vehicle_type IN ('MOTORBIKE','CAR','TRUCK','BICYCLE')),
    CONSTRAINT chk_pricing_rules_ctype
        CHECK (customer_type IN ('VISITOR','MONTHLY')),
    CONSTRAINT chk_pricing_rules_prices  CHECK (day_price >= 0 AND night_price >= 0),
    CONSTRAINT chk_pricing_rules_hours
        CHECK (day_start_hour >= 0 AND day_end_hour <= 24 AND day_end_hour > day_start_hour)
);
COMMENT ON TABLE pricing_rules IS 'Rule giá phẳng. Tên cũ: price_rules. Logic block do .NET tính.';
COMMENT ON COLUMN pricing_rules.day_price   IS 'Giá 1 block 4h trong giờ sáng (6-18h)';
COMMENT ON COLUMN pricing_rules.night_price IS 'Giá 1 block 4h trong giờ tối (18-24h)';

CREATE OR REPLACE VIEW price_rules AS SELECT * FROM pricing_rules;

CREATE INDEX idx_pricing_rules_table_id ON pricing_rules (price_table_id);
CREATE INDEX idx_pricing_rules_lookup   ON pricing_rules (price_table_id, vehicle_type, customer_type);

-- TABLE: fee_config
CREATE TABLE fee_config (
    id              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    config_key      VARCHAR(100)    NOT NULL UNIQUE,
    config_name     VARCHAR(255)    NOT NULL,
    amount          NUMERIC(12,2)   NOT NULL,
    unit            VARCHAR(50)     NOT NULL DEFAULT 'VND',
    description     TEXT            NULL,
    effective_from  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    is_active       BOOLEAN         NOT NULL DEFAULT TRUE,
    created_by      BIGINT          NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    updated_by      BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    created_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_fee_config_amount CHECK (amount >= 0)
);
COMMENT ON TABLE fee_config IS 'Cấu hình phí cố định: mất thẻ, đặt chỗ...';

CREATE INDEX idx_fee_config_key    ON fee_config (config_key);
CREATE INDEX idx_fee_config_active ON fee_config (is_active);

CREATE TRIGGER trg_fee_config_updated_at
    BEFORE UPDATE ON fee_config FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- =============================================================================
-- SECTION 9: SYSTEM CONFIGS (Spec 8.22) [F06]
-- =============================================================================

CREATE TABLE system_configs (
    id          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    config_key  VARCHAR(100)    NOT NULL UNIQUE,
    config_value TEXT           NOT NULL,
    description TEXT            NULL,
    updated_by  BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    updated_at  TIMESTAMPTZ     NOT NULL DEFAULT NOW()
);
COMMENT ON TABLE system_configs IS 'Cấu hình hệ thống key-value. Spec 8.22.';

CREATE INDEX idx_system_configs_key ON system_configs (config_key);

-- =============================================================================
-- SECTION 10: MONTHLY PASSES (was resident_subscriptions) [F07][F11]
-- Thiết kế phẳng theo Spec 8.15
-- =============================================================================

CREATE TABLE monthly_passes (
    id                      BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    driver_id               BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    owner_name              VARCHAR(255)    NOT NULL,
    phone                   VARCHAR(20)     NULL,
    plate_number            VARCHAR(20)     NULL,
    normalized_plate_number VARCHAR(20)     NULL,
    vehicle_type_id         BIGINT          NOT NULL REFERENCES vehicle_types(id) ON DELETE RESTRICT,
    vehicle_type            VARCHAR(30)     NOT NULL,
    parking_card_id         BIGINT          NULL REFERENCES parking_cards(id) ON DELETE SET NULL,
    status                  VARCHAR(30)     NOT NULL DEFAULT 'PENDING_VERIFICATION',
    start_date              DATE            NULL,
    end_date                DATE            NULL,
    activated_at            TIMESTAMPTZ     NULL,
    verified_by             BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    verified_at             TIMESTAMPTZ     NULL,
    rejection_reason        TEXT            NULL,
    expiry_warning_sent_at  TIMESTAMPTZ     NULL,
    notes                   TEXT            NULL,
    created_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    version                 INT             NOT NULL DEFAULT 0,

    CONSTRAINT chk_monthly_passes_status
        CHECK (status IN ('PENDING_VERIFICATION','ACTIVE','EXPIRING_SOON','EXPIRED','CANCELLED')),
    CONSTRAINT chk_monthly_passes_vtype
        CHECK (vehicle_type IN ('MOTORBIKE','CAR','TRUCK','BICYCLE')),
    CONSTRAINT chk_monthly_passes_dates
        CHECK (
            status = 'PENDING_VERIFICATION'
            OR (start_date IS NOT NULL AND end_date IS NOT NULL AND end_date >= start_date)
        )
);
COMMENT ON TABLE monthly_passes IS 'Vé tháng. Tên cũ: resident_subscriptions. Thiết kế phẳng Spec 8.15.';

CREATE OR REPLACE VIEW resident_subscriptions AS SELECT * FROM monthly_passes;

CREATE INDEX idx_monthly_passes_driver_id  ON monthly_passes (driver_id) WHERE driver_id IS NOT NULL;
CREATE INDEX idx_monthly_passes_plate      ON monthly_passes (normalized_plate_number)
    WHERE normalized_plate_number IS NOT NULL;
CREATE INDEX idx_monthly_passes_status     ON monthly_passes (status);
CREATE INDEX idx_monthly_passes_end_date   ON monthly_passes (end_date) WHERE status = 'ACTIVE';

CREATE TRIGGER trg_monthly_passes_updated_at
    BEFORE UPDATE ON monthly_passes FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

CREATE OR REPLACE FUNCTION fn_monthly_passes_normalize_plate()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.plate_number IS NOT NULL THEN
        NEW.normalized_plate_number = fn_normalize_plate(NEW.plate_number);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_monthly_passes_normalize
    BEFORE INSERT OR UPDATE ON monthly_passes
    FOR EACH ROW EXECUTE FUNCTION fn_monthly_passes_normalize_plate();

-- =============================================================================
-- SECTION 11: RESERVATIONS [F14]
-- slot_id -> original_spot_id + assigned_spot_id
-- =============================================================================

CREATE TABLE reservations (
    id                  BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    driver_id           BIGINT          NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    vehicle_id          BIGINT          NOT NULL REFERENCES vehicles(id) ON DELETE RESTRICT,
    original_spot_id    BIGINT          NULL REFERENCES slots(id) ON DELETE SET NULL,
    assigned_spot_id    BIGINT          NULL REFERENCES slots(id) ON DELETE SET NULL,
    status              VARCHAR(30)     NOT NULL DEFAULT 'PAYMENT_PENDING',
    reserved_start_time TIMESTAMPTZ     NOT NULL,
    hold_until          TIMESTAMPTZ     NOT NULL,
    reminder_sent_at    TIMESTAMPTZ     NULL,
    checked_in_at       TIMESTAMPTZ     NULL,
    extension_count     INT             NOT NULL DEFAULT 0,
    notes               TEXT            NULL,
    cancelled_reason    TEXT            NULL,
    cancelled_by        BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    created_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_reservations_status
        CHECK (status IN (
            'PAYMENT_PENDING','PAYMENT_REVIEW','CONFIRMED','CHECKED_IN',
            'EXPIRED','CANCELLED_BY_DRIVER','CANCELLED_BY_SYSTEM','REFUND_PENDING','REFUNDED'
        )),
    CONSTRAINT chk_reservations_hold_until      CHECK (hold_until >= reserved_start_time),
    CONSTRAINT chk_reservations_extension_count CHECK (extension_count >= 0)
);
COMMENT ON TABLE reservations IS 'Đặt chỗ ô tô B2. original_spot_id=slot gốc, assigned_spot_id=slot thực tế sau đổi.';

CREATE INDEX idx_reservations_driver_id  ON reservations (driver_id);
CREATE INDEX idx_reservations_vehicle_id ON reservations (vehicle_id);
CREATE INDEX idx_reservations_orig_spot  ON reservations (original_spot_id);
CREATE INDEX idx_reservations_asgn_spot  ON reservations (assigned_spot_id);
CREATE INDEX idx_reservations_status     ON reservations (status);
CREATE INDEX idx_reservations_hold_until ON reservations (hold_until) WHERE status = 'CONFIRMED';
CREATE INDEX idx_reservations_start_time ON reservations (reserved_start_time);

CREATE TRIGGER trg_reservations_updated_at
    BEFORE UPDATE ON reservations FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

CREATE OR REPLACE FUNCTION fn_reservations_protect_immutable()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.created_at != OLD.created_at THEN
        RAISE EXCEPTION 'reservations.created_at is immutable after creation';
    END IF;
    IF NEW.reserved_start_time != OLD.reserved_start_time THEN
        RAISE EXCEPTION 'reservations.reserved_start_time is immutable after creation';
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_reservations_protect_immutable
    BEFORE UPDATE ON reservations
    FOR EACH ROW EXECUTE FUNCTION fn_reservations_protect_immutable();

-- TABLE: reservation_assignment_history
CREATE TABLE reservation_assignment_history (
    id              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    reservation_id  BIGINT          NOT NULL REFERENCES reservations(id) ON DELETE RESTRICT,
    from_slot_id    BIGINT          NULL REFERENCES slots(id) ON DELETE SET NULL,
    to_slot_id      BIGINT          NOT NULL REFERENCES slots(id) ON DELETE RESTRICT,
    changed_by      BIGINT          NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    change_reason   VARCHAR(50)     NOT NULL,
    reason_notes    TEXT            NULL,
    changed_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_slot_history_reason
        CHECK (change_reason IN (
            'WRONG_PARKED','MAINTENANCE','DRIVER_REQUEST','STAFF_OVERRIDE','SYSTEM_REALLOCATION'
        )),
    CONSTRAINT chk_slot_history_different
        CHECK (from_slot_id IS NULL OR from_slot_id != to_slot_id)
);
COMMENT ON TABLE reservation_assignment_history IS 'Lịch sử đổi slot reservation. Append-only.';

CREATE INDEX idx_slot_history_reservation_id ON reservation_assignment_history (reservation_id);
CREATE INDEX idx_slot_history_changed_at     ON reservation_assignment_history (changed_at);
CREATE INDEX idx_slot_history_to_slot        ON reservation_assignment_history (to_slot_id);

-- =============================================================================
-- SECTION 12: PARKING SESSIONS (CORE ENTITY) [F08]
-- =============================================================================

CREATE TABLE parking_sessions (
    id                          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    session_code                VARCHAR(50)     NOT NULL UNIQUE,

    -- Card
    card_id                     BIGINT          NOT NULL REFERENCES parking_cards(id) ON DELETE RESTRICT,

    -- Vehicle info [F08]
    vehicle_type                VARCHAR(30)     NOT NULL,
    vehicle_type_id             BIGINT          NULL REFERENCES vehicle_types(id) ON DELETE SET NULL,
    no_plate                    BOOLEAN         NOT NULL DEFAULT FALSE,
    license_plate_entry         VARCHAR(20)     NULL,
    plate_normalized_entry      VARCHAR(20)     NULL,
    license_plate_exit          VARCHAR(20)     NULL,
    vehicle_description         TEXT            NULL,
    vehicle_image_url_entry     VARCHAR(500)    NULL,
    vehicle_image_url_exit      VARCHAR(500)    NULL,

    -- Customer
    customer_type               VARCHAR(20)     NOT NULL DEFAULT 'VISITOR',
    driver_id                   BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    subscription_id             BIGINT          NULL REFERENCES monthly_passes(id) ON DELETE SET NULL,
    reservation_id              BIGINT          NULL REFERENCES reservations(id) ON DELETE SET NULL,

    -- Location
    floor_id                    BIGINT          NOT NULL REFERENCES floors(id) ON DELETE RESTRICT,
    area_id                     BIGINT          NOT NULL REFERENCES areas(id) ON DELETE RESTRICT,
    slot_id                     BIGINT          NULL REFERENCES slots(id) ON DELETE SET NULL,
    entry_gate_id               BIGINT          NOT NULL REFERENCES gates(id) ON DELETE RESTRICT,
    exit_gate_id                BIGINT          NULL REFERENCES gates(id) ON DELETE SET NULL,

    -- Suggestion cols [F08]
    suggested_area_id           BIGINT          NULL REFERENCES areas(id) ON DELETE SET NULL,
    suggested_slot_id           BIGINT          NULL REFERENCES slots(id) ON DELETE SET NULL,
    override_area_id            BIGINT          NULL REFERENCES areas(id) ON DELETE SET NULL,
    override_slot_id            BIGINT          NULL REFERENCES slots(id) ON DELETE SET NULL,
    override_reason             TEXT            NULL,

    -- Status
    status                      VARCHAR(30)     NOT NULL DEFAULT 'ACTIVE',
    payment_required            BOOLEAN         NOT NULL DEFAULT TRUE,

    -- Timing
    entry_time                  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    exit_time                   TIMESTAMPTZ     NULL,
    duration_minutes            INT             NULL,

    -- Pricing snapshot phẳng [F08] + JSONB backward compat
    price_table_id              BIGINT          NULL REFERENCES price_tables(id) ON DELETE SET NULL,
    snapshot_day_price          NUMERIC(12,2)   NULL,
    snapshot_night_price        NUMERIC(12,2)   NULL,
    snapshot_monthly_price      NUMERIC(12,2)   NULL,
    snapshot_lost_card_fee      NUMERIC(12,2)   NULL,
    pricing_snapshot            JSONB           NULL,

    -- Fees
    calculated_fee              NUMERIC(12,2)   NULL,
    final_fee                   NUMERIC(12,2)   NULL,

    -- Staff & metadata
    entry_staff_id              BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    exit_staff_id               BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    cancellation_reason         TEXT            NULL,
    cancelled_by                BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    notes                       TEXT            NULL,
    created_at                  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at                  TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    version                     INT             NOT NULL DEFAULT 0,

    CONSTRAINT chk_sessions_vehicle_type
        CHECK (vehicle_type IN ('MOTORBIKE','CAR','TRUCK','BICYCLE')),
    CONSTRAINT chk_sessions_customer_type
        CHECK (customer_type IN ('VISITOR','MONTHLY')),
    CONSTRAINT chk_sessions_status
        CHECK (status IN (
            'ACTIVE','PENDING_PAYMENT','PAID_WAITING_EXIT','COMPLETED',
            'LOST_CARD_PENDING','LOST_CARD_APPROVED','PLATE_MISMATCH',
            'VIOLATION_RECORDED','CANCELLED','BLOCKED'
        )),
    CONSTRAINT chk_sessions_exit_after_entry
        CHECK (exit_time IS NULL OR exit_time >= entry_time)
);
COMMENT ON TABLE parking_sessions IS 'Entity trung tâm. Snapshot giá tách cột phẳng. Không xóa vật lý.';
COMMENT ON COLUMN parking_sessions.session_code IS 'Định dạng PS-YYYYMMDD-NNNNN';
COMMENT ON COLUMN parking_sessions.duration_minutes IS 'Tự động tính bởi trigger khi exit_time được set';
COMMENT ON COLUMN parking_sessions.cancellation_reason IS 'Tên mới. Tên cũ: cancel_reason';

-- Trigger: tính duration_minutes
CREATE OR REPLACE FUNCTION fn_sessions_calc_duration()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.exit_time IS NOT NULL THEN
        NEW.duration_minutes := EXTRACT(EPOCH FROM (NEW.exit_time - NEW.entry_time))::INT / 60;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_sessions_calc_duration
    BEFORE INSERT OR UPDATE ON parking_sessions
    FOR EACH ROW EXECUTE FUNCTION fn_sessions_calc_duration();

-- Trigger: normalize plate entry
CREATE OR REPLACE FUNCTION fn_sessions_normalize_plates()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.license_plate_entry IS NOT NULL THEN
        NEW.plate_normalized_entry = fn_normalize_plate(NEW.license_plate_entry);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_sessions_normalize_plates
    BEFORE INSERT OR UPDATE ON parking_sessions
    FOR EACH ROW EXECUTE FUNCTION fn_sessions_normalize_plates();

CREATE TRIGGER trg_sessions_updated_at
    BEFORE UPDATE ON parking_sessions FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- Trigger: cập nhật area occupancy [F17] - có xử lý UPDATE area_id
CREATE OR REPLACE FUNCTION fn_update_area_occupancy()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'INSERT' AND NEW.status = 'ACTIVE' THEN
        UPDATE areas
        SET current_occupancy = current_occupancy + 1, updated_at = NOW()
        WHERE id = NEW.area_id;
    END IF;

    IF TG_OP = 'UPDATE' THEN
        -- [F17] Xử lý khi Staff đổi area_id (chuyển session sang khu khác)
        IF OLD.area_id IS DISTINCT FROM NEW.area_id
           AND OLD.status NOT IN ('COMPLETED','CANCELLED')
           AND NEW.status NOT IN ('COMPLETED','CANCELLED') THEN
            -- Hoàn lại khu cũ
            UPDATE areas
            SET current_occupancy = GREATEST(0, current_occupancy - 1), updated_at = NOW()
            WHERE id = OLD.area_id;
            -- Tăng khu mới
            UPDATE areas
            SET current_occupancy = current_occupancy + 1, updated_at = NOW()
            WHERE id = NEW.area_id;

        -- Session hoàn thành hoặc hủy -> giải phóng occupancy
        ELSIF OLD.status NOT IN ('COMPLETED','CANCELLED')
          AND NEW.status IN ('COMPLETED','CANCELLED') THEN
            UPDATE areas
            SET current_occupancy = GREATEST(0, current_occupancy - 1), updated_at = NOW()
            WHERE id = NEW.area_id;
        END IF;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_sessions_area_occupancy
    AFTER INSERT OR UPDATE ON parking_sessions
    FOR EACH ROW EXECUTE FUNCTION fn_update_area_occupancy();

-- Partial unique indexes
CREATE UNIQUE INDEX uq_sessions_card_active
    ON parking_sessions (card_id)
    WHERE status NOT IN ('COMPLETED','CANCELLED');

CREATE UNIQUE INDEX uq_sessions_reservation
    ON parking_sessions (reservation_id)
    WHERE reservation_id IS NOT NULL AND status NOT IN ('CANCELLED');

-- Regular indexes
CREATE INDEX idx_sessions_card_id     ON parking_sessions (card_id);
CREATE INDEX idx_sessions_status      ON parking_sessions (status);
CREATE INDEX idx_sessions_driver_id   ON parking_sessions (driver_id) WHERE driver_id IS NOT NULL;
CREATE INDEX idx_sessions_floor_id    ON parking_sessions (floor_id);
CREATE INDEX idx_sessions_area_id     ON parking_sessions (area_id);
CREATE INDEX idx_sessions_slot_id     ON parking_sessions (slot_id) WHERE slot_id IS NOT NULL;
CREATE INDEX idx_sessions_entry_time  ON parking_sessions (entry_time DESC);
CREATE INDEX idx_sessions_plate_entry ON parking_sessions (plate_normalized_entry)
    WHERE plate_normalized_entry IS NOT NULL;
CREATE INDEX idx_sessions_date_status ON parking_sessions (entry_time, status);

-- =============================================================================
-- SECTION 13: ADD FK current_session_id vào parking_cards và slots [F12][F13]
-- =============================================================================

ALTER TABLE parking_cards
    ADD CONSTRAINT fk_parking_cards_current_session
    FOREIGN KEY (current_session_id) REFERENCES parking_sessions(id) ON DELETE SET NULL;

CREATE INDEX idx_parking_cards_curr_session ON parking_cards (current_session_id)
    WHERE current_session_id IS NOT NULL;

ALTER TABLE slots
    ADD CONSTRAINT fk_slots_current_session
    FOREIGN KEY (current_session_id) REFERENCES parking_sessions(id) ON DELETE SET NULL;

CREATE INDEX idx_slots_current_session ON slots (current_session_id)
    WHERE current_session_id IS NOT NULL;

-- =============================================================================
-- SECTION 14: PAYMENTS (was payment_transactions) [F07][F15]
-- =============================================================================

CREATE TABLE payments (
    id                  BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    transaction_code    VARCHAR(50)     NOT NULL UNIQUE,
    session_id          BIGINT          NULL REFERENCES parking_sessions(id) ON DELETE RESTRICT,
    reservation_id      BIGINT          NULL REFERENCES reservations(id) ON DELETE RESTRICT,
    lost_card_case_id   BIGINT          NULL,   -- FK thêm sau
    purpose             VARCHAR(40)     NOT NULL,
    payment_method      VARCHAR(20)     NOT NULL,
    status              VARCHAR(20)     NOT NULL DEFAULT 'PENDING',
    amount              NUMERIC(12,2)   NOT NULL,
    currency            VARCHAR(10)     NOT NULL DEFAULT 'VND',
    waive_reason        VARCHAR(100)    NULL,
    payment_ref         VARCHAR(255)    NULL UNIQUE,
    qr_code_data        TEXT            NULL,
    confirmed_by        BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    confirmed_at        TIMESTAMPTZ     NULL,
    confirmation_note   TEXT            NULL,
    evidence_url        VARCHAR(500)    NULL,
    paid_at             TIMESTAMPTZ     NULL,
    expires_at          TIMESTAMPTZ     NULL,
    refunded_at         TIMESTAMPTZ     NULL,
    refund_reason       TEXT            NULL,
    refunded_by         BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    created_by          BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    created_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_payments_purpose
        CHECK (purpose IN (
            'PARKING_FEE','RESERVATION_FEE','RESERVATION_EXTENSION_FEE',
            'LOST_CARD_FEE','PENALTY_FEE','SUPPLEMENTARY_FEE','REFUND'
        )),
    CONSTRAINT chk_payments_method
        CHECK (payment_method IN ('CASH','VIETQR','WAIVED','NOT_REQUIRED')),
    CONSTRAINT chk_payments_status
        CHECK (status IN (
            'PENDING','PAID','FAILED','CANCELLED','EXPIRED',
            'PAYMENT_REVIEW','REFUND_PENDING','REFUNDED'
        )),
    CONSTRAINT chk_payments_amount CHECK (amount >= 0),
    CONSTRAINT chk_payments_vietqr_ref
        CHECK (payment_method != 'VIETQR' OR payment_ref IS NOT NULL),
    CONSTRAINT chk_payments_source
        CHECK (
            session_id IS NOT NULL
            OR reservation_id IS NOT NULL
            OR lost_card_case_id IS NOT NULL
        )
);
COMMENT ON TABLE payments IS 'Giao dịch thanh toán. Tên cũ: payment_transactions. PAID không được sửa.';
COMMENT ON COLUMN payments.waive_reason IS 'Lý do miễn phí nếu payment_method=WAIVED';

CREATE OR REPLACE VIEW payment_transactions AS SELECT * FROM payments;

CREATE OR REPLACE FUNCTION fn_payment_protect_completed()
RETURNS TRIGGER AS $$
BEGIN
    IF OLD.status IN ('PAID','REFUNDED') THEN
        RAISE EXCEPTION 'Cannot modify payment with status %. Create a new transaction instead.', OLD.status;
    END IF;
    IF NEW.created_at != OLD.created_at THEN
        RAISE EXCEPTION 'payments.created_at is immutable';
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_payment_protect_completed
    BEFORE UPDATE ON payments
    FOR EACH ROW EXECUTE FUNCTION fn_payment_protect_completed();

CREATE TRIGGER trg_payment_updated_at
    BEFORE UPDATE ON payments FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

CREATE INDEX idx_payments_session_id     ON payments (session_id)     WHERE session_id IS NOT NULL;
CREATE INDEX idx_payments_reservation_id ON payments (reservation_id) WHERE reservation_id IS NOT NULL;
CREATE INDEX idx_payments_status         ON payments (status);
CREATE INDEX idx_payments_method         ON payments (payment_method);
CREATE INDEX idx_payments_purpose        ON payments (purpose);
CREATE INDEX idx_payments_payment_ref    ON payments (payment_ref)    WHERE payment_ref IS NOT NULL;
CREATE INDEX idx_payments_created_at     ON payments (created_at DESC);
CREATE INDEX idx_payments_date_status    ON payments (created_at, status);

-- TABLE: receipts
CREATE TABLE receipts (
    id                  BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    receipt_code        VARCHAR(50)     NOT NULL UNIQUE,
    session_id          BIGINT          NULL REFERENCES parking_sessions(id) ON DELETE RESTRICT,
    reservation_id      BIGINT          NULL REFERENCES reservations(id) ON DELETE RESTRICT,
    total_amount        NUMERIC(12,2)   NOT NULL,
    payment_method      VARCHAR(20)     NOT NULL,
    customer_name       VARCHAR(255)    NULL,
    license_plate       VARCHAR(20)     NULL,
    vehicle_type        VARCHAR(30)     NULL,
    entry_time          TIMESTAMPTZ     NULL,
    exit_time           TIMESTAMPTZ     NULL,
    duration_minutes    INT             NULL,
    fee_breakdown       JSONB           NOT NULL DEFAULT '{}',
    created_by          BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    created_at          TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_receipts_amount CHECK (total_amount >= 0)
);
COMMENT ON TABLE receipts IS 'Phiếu thu. Append-only.';

CREATE INDEX idx_receipts_session_id     ON receipts (session_id)     WHERE session_id IS NOT NULL;
CREATE INDEX idx_receipts_reservation_id ON receipts (reservation_id) WHERE reservation_id IS NOT NULL;
CREATE INDEX idx_receipts_created_at     ON receipts (created_at DESC);

-- =============================================================================
-- SECTION 15: INCIDENT & EXCEPTION HANDLING
-- =============================================================================

CREATE TABLE lost_card_cases (
    id                      BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    case_code               VARCHAR(50)     NOT NULL UNIQUE,
    session_id              BIGINT          NOT NULL REFERENCES parking_sessions(id) ON DELETE RESTRICT,
    status                  VARCHAR(20)     NOT NULL DEFAULT 'PENDING_REVIEW',
    id_document_type        VARCHAR(50)     NULL,
    id_document_number      VARCHAR(50)     NULL,
    id_document_image_url   VARCHAR(500)    NULL,
    reporter_phone          VARCHAR(20)     NULL,
    reporter_name           VARCHAR(255)    NULL,
    description             TEXT            NULL,
    lost_card_fee           NUMERIC(12,2)   NOT NULL DEFAULT 150000,
    additional_parking_fee  NUMERIC(12,2)   NULL,
    total_fee               NUMERIC(12,2)   GENERATED ALWAYS AS (
                                COALESCE(lost_card_fee, 0) + COALESCE(additional_parking_fee, 0)
                            ) STORED,
    reported_by             BIGINT          NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    reported_at             TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    reviewed_by             BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    reviewed_at             TIMESTAMPTZ     NULL,
    review_notes            TEXT            NULL,
    payment_id              BIGINT          NULL,   -- FK thêm sau
    created_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_lost_card_status
        CHECK (status IN ('PENDING_REVIEW','APPROVED','REJECTED','RESOLVED')),
    CONSTRAINT chk_lost_card_fee CHECK (lost_card_fee >= 0)
);
COMMENT ON TABLE lost_card_cases IS 'Hồ sơ mất thẻ. Staff tạo -> Manager duyệt.';

ALTER TABLE lost_card_cases
    ADD CONSTRAINT fk_lost_card_payment
    FOREIGN KEY (payment_id) REFERENCES payments(id) ON DELETE SET NULL;

ALTER TABLE payments
    ADD CONSTRAINT fk_payment_lost_card
    FOREIGN KEY (lost_card_case_id) REFERENCES lost_card_cases(id) ON DELETE SET NULL;

CREATE INDEX idx_lost_card_session_id  ON lost_card_cases (session_id);
CREATE INDEX idx_lost_card_status      ON lost_card_cases (status);
CREATE INDEX idx_lost_card_reported_by ON lost_card_cases (reported_by);

CREATE TRIGGER trg_lost_card_updated_at
    BEFORE UPDATE ON lost_card_cases FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

CREATE TABLE plate_mismatch_cases (
    id                      BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    case_code               VARCHAR(50)     NOT NULL UNIQUE,
    session_id              BIGINT          NOT NULL REFERENCES parking_sessions(id) ON DELETE RESTRICT,
    plate_at_entry          VARCHAR(20)     NOT NULL,
    plate_at_exit           VARCHAR(20)     NOT NULL,
    plate_entry_image_url   VARCHAR(500)    NULL,
    plate_exit_image_url    VARCHAR(500)    NULL,
    status                  VARCHAR(20)     NOT NULL DEFAULT 'PENDING',
    detected_by             BIGINT          NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    detected_at             TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    resolved_by             BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    resolved_at             TIMESTAMPTZ     NULL,
    resolution_reason       TEXT            NULL,
    created_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_mismatch_status
        CHECK (status IN ('PENDING','CONFIRMED_OK','REJECTED'))
);
COMMENT ON TABLE plate_mismatch_cases IS 'Hồ sơ sai biển số. Staff phát hiện -> Manager xác nhận.';

CREATE INDEX idx_mismatch_session_id ON plate_mismatch_cases (session_id);
CREATE INDEX idx_mismatch_status     ON plate_mismatch_cases (status);

CREATE TRIGGER trg_mismatch_updated_at
    BEFORE UPDATE ON plate_mismatch_cases FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

CREATE TABLE incident_reports (
    id                      BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    report_code             VARCHAR(50)     NOT NULL UNIQUE,
    session_id              BIGINT          NULL REFERENCES parking_sessions(id) ON DELETE SET NULL,
    slot_id                 BIGINT          NULL REFERENCES slots(id) ON DELETE SET NULL,
    area_id                 BIGINT          NULL REFERENCES areas(id) ON DELETE SET NULL,
    incident_type           VARCHAR(30)     NOT NULL,
    status                  VARCHAR(20)     NOT NULL DEFAULT 'OPEN',
    description             TEXT            NOT NULL,
    evidence_image_urls     TEXT[]          NULL,
    penalty_fee             NUMERIC(12,2)   NULL,
    penalty_start_at        TIMESTAMPTZ     NULL,
    payment_id              BIGINT          NULL REFERENCES payments(id) ON DELETE SET NULL,
    reported_by             BIGINT          NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    reported_at             TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    resolved_by             BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    resolved_at             TIMESTAMPTZ     NULL,
    resolution_notes        TEXT            NULL,
    created_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_incident_type
        CHECK (incident_type IN ('WRONG_SLOT','WRONG_AREA','PLATE_MISMATCH','UNAUTHORIZED_ENTRY','OTHER')),
    CONSTRAINT chk_incident_status
        CHECK (status IN ('OPEN','UNDER_REVIEW','RESOLVED','DISMISSED'))
);
COMMENT ON TABLE incident_reports IS 'Vi phạm/sự cố. penalty_days tính qua view. Không dùng GENERATED AS NOW().';

CREATE INDEX idx_incidents_session_id  ON incident_reports (session_id) WHERE session_id IS NOT NULL;
CREATE INDEX idx_incidents_slot_id     ON incident_reports (slot_id)    WHERE slot_id IS NOT NULL;
CREATE INDEX idx_incidents_status      ON incident_reports (status);
CREATE INDEX idx_incidents_type        ON incident_reports (incident_type);
CREATE INDEX idx_incidents_reported_at ON incident_reports (reported_at DESC);

CREATE TRIGGER trg_incidents_updated_at
    BEFORE UPDATE ON incident_reports FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();

-- View: tính penalty_days động (tránh GENERATED AS NOW())
CREATE OR REPLACE VIEW vw_incident_penalty AS
SELECT
    ir.*,
    CASE
        WHEN ir.penalty_start_at IS NOT NULL
        THEN CEIL(EXTRACT(EPOCH FROM (NOW() - ir.penalty_start_at)) / 86400)::INT
        ELSE 0
    END AS penalty_days
FROM incident_reports ir;

