    content         TEXT            NOT NULL,
    rating          INT             NULL,
    status          VARCHAR(20)     NOT NULL DEFAULT 'PENDING',
    response_by     BIGINT          NULL REFERENCES users(id) ON DELETE SET NULL,
    response_text   TEXT            NULL,
    responded_at    TIMESTAMPTZ     NULL,
    created_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),

    CONSTRAINT chk_feedbacks_rating  CHECK (rating IS NULL OR (rating >= 1 AND rating <= 5)),
    CONSTRAINT chk_feedbacks_type    CHECK (feedback_type IN ('LOST_CARD','WRONG_FEE','SLOT_OCCUPIED','GENERAL','COMPLAINT')),
    CONSTRAINT chk_feedbacks_status  CHECK (status IN ('PENDING','UNDER_REVIEW','RESOLVED','DISMISSED'))
);
COMMENT ON TABLE feedbacks IS 'Phản hồi/khiếu nại của Driver.';

