-- =============================================================================
-- SECTION 19: AUDIT LOG (PARTITIONED BY MONTH)
-- [F02] BIGINT GENERATED BY DEFAULT AS IDENTITY
-- Composite PK (id, created_at) bắt buộc cho partitioned table
-- =============================================================================

CREATE TABLE audit_logs (
    id              BIGINT          NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    created_at      TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    actor_id        BIGINT          NULL,
    actor_username  VARCHAR(100)    NULL,
    actor_role      VARCHAR(20)     NULL,
    category        VARCHAR(30)     NOT NULL,
    action          VARCHAR(100)    NOT NULL,
    entity_type     VARCHAR(50)     NULL,
    entity_id       BIGINT          NULL,
    old_values      JSONB           NULL,
    new_values      JSONB           NULL,
    ip_address      INET            NULL,
    user_agent      TEXT            NULL,
    request_id      VARCHAR(100)    NULL,
    backend_source  VARCHAR(20)     NULL,
    notes           TEXT            NULL,
    severity        VARCHAR(20)     NOT NULL DEFAULT 'INFO',

    CONSTRAINT chk_audit_category
        CHECK (category IN (
            'AUTH','USER_MANAGEMENT','FACILITY','PRICING','SESSION','PAYMENT',
            'RESERVATION','LOST_CARD','PLATE_MISMATCH','INCIDENT','SUBSCRIPTION',
            'SYSTEM','REPORT'
        )),
    CONSTRAINT chk_audit_severity CHECK (severity IN ('INFO','WARNING','CRITICAL')),
    PRIMARY KEY (id, created_at)

) PARTITION BY RANGE (created_at);

COMMENT ON TABLE audit_logs IS 'Append-only audit trail. Partition theo tháng. Không xóa vật lý.';
COMMENT ON COLUMN audit_logs.actor_username IS 'Denormalized - không JOIN users để performance';

