CREATE OR REPLACE FUNCTION fn_write_audit_log(
    p_actor_id          BIGINT,
    p_actor_username    TEXT,
    p_actor_role        TEXT,
    p_category          TEXT,
    p_action            TEXT,
    p_entity_type       TEXT,
    p_entity_id         BIGINT,
    p_old_values        JSONB,
    p_new_values        JSONB,
    p_notes             TEXT,
    p_backend_source    TEXT,
    p_severity          TEXT DEFAULT 'INFO'
)
RETURNS VOID AS $$
BEGIN
    INSERT INTO audit_logs (
        actor_id, actor_username, actor_role,
        category, action, entity_type, entity_id,
        old_values, new_values,
        notes, backend_source, severity
    ) VALUES (
        p_actor_id, p_actor_username, p_actor_role,
        p_category, p_action, p_entity_type, p_entity_id,
        p_old_values, p_new_values,
        p_notes, p_backend_source, p_severity
    );
END;
$$ LANGUAGE plpgsql;

-- =============================================================================
-- SECTION 20: MATERIALIZED VIEWS & VIEWS
-- [F18] UNIQUE INDEX phải tạo TRƯỚC REFRESH CONCURRENTLY
-- =============================================================================

CREATE MATERIALIZED VIEW mv_daily_revenue AS
SELECT
    DATE(pt.created_at AT TIME ZONE 'Asia/Ho_Chi_Minh')  AS revenue_date,
    pt.payment_method,
    ps.vehicle_type,
    COUNT(pt.id)                                          AS transaction_count,
    SUM(pt.amount)                                        AS total_revenue,
    SUM(CASE WHEN pt.purpose = 'PARKING_FEE'         THEN pt.amount ELSE 0 END) AS parking_fee_revenue,
    SUM(CASE WHEN pt.purpose = 'RESERVATION_FEE'     THEN pt.amount ELSE 0 END) AS reservation_fee_revenue,
    SUM(CASE WHEN pt.purpose = 'LOST_CARD_FEE'       THEN pt.amount ELSE 0 END) AS lost_card_fee_revenue,
    SUM(CASE WHEN pt.purpose = 'PENALTY_FEE'         THEN pt.amount ELSE 0 END) AS penalty_fee_revenue
FROM payments pt
LEFT JOIN parking_sessions ps ON pt.session_id = ps.id
WHERE pt.status = 'PAID'
GROUP BY
    DATE(pt.created_at AT TIME ZONE 'Asia/Ho_Chi_Minh'),
    pt.payment_method,
    ps.vehicle_type
WITH DATA;

-- [F18] UNIQUE INDEX trước -> REFRESH CONCURRENTLY an toàn
CREATE UNIQUE INDEX idx_mv_daily_revenue_unique
    ON mv_daily_revenue (revenue_date, payment_method, vehicle_type);

CREATE MATERIALIZED VIEW mv_slot_occupancy AS
SELECT
    f.id                AS floor_id,
    f.floor_code,
    a.id                AS area_id,
    a.area_code,
    COUNT(s.id)         AS total_slots,
    SUM(CASE WHEN s.status = 'AVAILABLE'    THEN 1 ELSE 0 END) AS available_slots,
    SUM(CASE WHEN s.status = 'OCCUPIED'     THEN 1 ELSE 0 END) AS occupied_slots,
    SUM(CASE WHEN s.status = 'RESERVED'     THEN 1 ELSE 0 END) AS reserved_slots,
    SUM(CASE WHEN s.status = 'MAINTENANCE'  THEN 1 ELSE 0 END) AS maintenance_slots,
    ROUND(
        100.0 * SUM(CASE WHEN s.status = 'OCCUPIED' THEN 1 ELSE 0 END)
        / NULLIF(COUNT(s.id), 0), 2
    ) AS occupancy_rate
FROM floors f
JOIN areas  a ON a.floor_id = f.id
JOIN slots  s ON s.area_id = a.id
GROUP BY f.id, f.floor_code, a.id, a.area_code
WITH DATA;

-- [F18]
CREATE UNIQUE INDEX idx_mv_slot_occupancy_unique ON mv_slot_occupancy (floor_id, area_id);

-- Views thông dụng
CREATE OR REPLACE VIEW vw_area_capacity AS
SELECT
    f.floor_code,
    f.management_type,
    a.area_code,
    a.total_capacity,
    a.current_occupancy,
    a.total_capacity - a.current_occupancy  AS available_capacity,
    ROUND(100.0 * a.current_occupancy / NULLIF(a.total_capacity, 0), 2) AS occupancy_rate,
    a.status
FROM floors f
JOIN areas a ON a.floor_id = f.id
WHERE a.status = 'ACTIVE'
ORDER BY f.floor_order, a.display_order;

CREATE OR REPLACE VIEW vw_active_sessions AS
SELECT
    s.id,
    s.session_code,
    s.license_plate_entry,
    s.vehicle_type,
    s.customer_type,
    s.entry_time,
    EXTRACT(EPOCH FROM (NOW() - s.entry_time))::INT / 60 AS current_duration_minutes,
    s.status,
    f.floor_code,
    a.area_code,
    sl.slot_code,
    c.card_code,
    g.gate_code AS entry_gate_code
FROM parking_sessions s
JOIN parking_cards  c  ON c.id = s.card_id
JOIN floors         f  ON f.id = s.floor_id
JOIN areas          a  ON a.id = s.area_id
LEFT JOIN slots     sl ON sl.id = s.slot_id
LEFT JOIN gates     g  ON g.id = s.entry_gate_id
WHERE s.status NOT IN ('COMPLETED','CANCELLED');

-- =============================================================================
-- SECTION 21: BUSINESS RULE TRIGGERS
-- =============================================================================

-- Subscription chỉ cho RESIDENT
CREATE OR REPLACE FUNCTION fn_check_subscription_resident()
RETURNS TRIGGER AS $$
DECLARE
    v_driver_type VARCHAR(20);
BEGIN
    IF NEW.driver_id IS NOT NULL THEN
        SELECT dp.driver_type INTO v_driver_type
        FROM driver_profiles dp WHERE dp.user_id = NEW.driver_id;
        IF v_driver_type IS NOT NULL AND v_driver_type != 'RESIDENT' THEN
            RAISE EXCEPTION 'Monthly pass chỉ dành cho Resident. User % có driver_type = %',
                NEW.driver_id, v_driver_type;
        END IF;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_monthly_pass_check_resident
    BEFORE INSERT ON monthly_passes
    FOR EACH ROW EXECUTE FUNCTION fn_check_subscription_resident();

-- Reservation chỉ cho CAR tại tầng AREA_AND_SLOT [F16]
CREATE OR REPLACE FUNCTION fn_check_reservation_car_b2()
RETURNS TRIGGER AS $$
DECLARE
    v_vehicle_type  VARCHAR(30);
    v_mgmt_type     VARCHAR(30);
    v_slot_id       BIGINT;
BEGIN
    SELECT v.vehicle_type INTO v_vehicle_type FROM vehicles v WHERE v.id = NEW.vehicle_id;

    -- Dùng assigned_spot_id hoặc original_spot_id
    v_slot_id := COALESCE(NEW.assigned_spot_id, NEW.original_spot_id);

    IF v_slot_id IS NOT NULL THEN
        SELECT f.management_type INTO v_mgmt_type
        FROM slots sl
        JOIN areas a  ON a.id = sl.area_id
        JOIN floors f ON f.id = a.floor_id
        WHERE sl.id = v_slot_id;
    END IF;

    IF v_vehicle_type != 'CAR' THEN
        RAISE EXCEPTION 'Reservation chỉ dành cho xe CAR. Vehicle % có type = %',
            NEW.vehicle_id, v_vehicle_type;
    END IF;

    -- [F16] Không hardcode 'B2' - check management_type thay vào
    IF v_slot_id IS NOT NULL AND v_mgmt_type IS DISTINCT FROM 'AREA_AND_SLOT' THEN
        RAISE EXCEPTION 'Reservation chỉ áp dụng tại tầng AREA_AND_SLOT. Slot nằm ở tầng type = %',
            v_mgmt_type;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_reservation_check_car_b2
    BEFORE INSERT ON reservations
    FOR EACH ROW EXECUTE FUNCTION fn_check_reservation_car_b2();

-- Quản lý slot status khi reservation thay đổi
CREATE OR REPLACE FUNCTION fn_reserve_slot_on_reservation()
RETURNS TRIGGER AS $$
DECLARE
    v_active_slot BIGINT;
BEGIN
    v_active_slot := COALESCE(NEW.assigned_spot_id, NEW.original_spot_id);

    IF NEW.status = 'CONFIRMED'
       AND (OLD.status IS NULL OR OLD.status IN ('PAYMENT_PENDING','PAYMENT_REVIEW')) THEN
        UPDATE slots SET status = 'RESERVED', updated_at = NOW()
        WHERE id = v_active_slot AND status = 'AVAILABLE';
        IF NOT FOUND THEN
            RAISE EXCEPTION 'Slot % không còn AVAILABLE để RESERVE', v_active_slot;
        END IF;
    END IF;

    IF NEW.status IN ('EXPIRED','CANCELLED_BY_DRIVER','CANCELLED_BY_SYSTEM') THEN
        UPDATE slots SET status = 'AVAILABLE', updated_at = NOW()
        WHERE id = v_active_slot AND status = 'RESERVED';
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_reservation_manage_slot
    AFTER INSERT OR UPDATE ON reservations
    FOR EACH ROW EXECUTE FUNCTION fn_reserve_slot_on_reservation();

-- =============================================================================
-- SECTION 22: HELPER FUNCTIONS
-- =============================================================================

CREATE OR REPLACE FUNCTION fn_calculate_parking_fee(
    p_session_id    BIGINT,
    p_exit_time     TIMESTAMPTZ DEFAULT NULL
)
RETURNS JSONB AS $$
DECLARE
    v_session       RECORD;
    v_exit_time     TIMESTAMPTZ;
    v_duration_min  INT;
BEGIN
    SELECT * INTO v_session FROM parking_sessions WHERE id = p_session_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Session % not found', p_session_id;
    END IF;

    v_exit_time    := COALESCE(p_exit_time, NOW());
    v_duration_min := EXTRACT(EPOCH FROM (v_exit_time - v_session.entry_time))::INT / 60;

    IF v_duration_min <= 15 THEN
        RETURN jsonb_build_object(
            'total_fee', 0,
            'free_period', TRUE,
            'duration_minutes', v_duration_min
        );
    END IF;

    RETURN jsonb_build_object(
        'session_id',           p_session_id,
        'customer_type',        v_session.customer_type,
        'duration_minutes',     v_duration_min,
        'entry_time',           v_session.entry_time,
        'exit_time',            v_exit_time,
        'snapshot_day_price',   v_session.snapshot_day_price,
        'snapshot_night_price', v_session.snapshot_night_price,
        'preview_only',         TRUE,
        'note',                 'Use .NET FeeCalculationService for official fee'
    );
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION fn_check_area_capacity(
    p_area_id       BIGINT,
    p_vehicle_type  VARCHAR
)
RETURNS BOOLEAN AS $$
DECLARE
    v_area RECORD;
BEGIN
    SELECT a.* INTO v_area FROM areas a WHERE a.id = p_area_id AND a.status = 'ACTIVE';
    IF NOT FOUND THEN RETURN FALSE; END IF;
    -- Kiểm tra loại xe qua area_vehicle_types (thay vì TEXT[])
    IF NOT EXISTS (
        SELECT 1 FROM area_vehicle_types avt
        JOIN vehicle_types vt ON vt.id = avt.vehicle_type_id
        WHERE avt.area_id = p_area_id AND vt.code = p_vehicle_type
    ) THEN RETURN FALSE; END IF;
    RETURN v_area.current_occupancy < v_area.total_capacity;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION fn_get_available_slots(
    p_area_id   BIGINT,
    p_limit     INT DEFAULT 10
)
RETURNS TABLE (slot_id BIGINT, slot_code TEXT, slot_number INT, is_premium BOOLEAN) AS $$
BEGIN
    RETURN QUERY
    SELECT s.id, s.slot_code::TEXT, s.slot_number, s.is_premium
    FROM slots s
    WHERE s.area_id = p_area_id AND s.status = 'AVAILABLE'
    ORDER BY s.is_premium DESC, s.slot_number ASC
    LIMIT p_limit;
END;
$$ LANGUAGE plpgsql STABLE;

CREATE OR REPLACE FUNCTION fn_expire_reservations()
RETURNS INT AS $$
DECLARE
    v_count INT;
BEGIN
    WITH expired AS (
        UPDATE reservations
        SET status = 'EXPIRED', updated_at = NOW()
        WHERE status = 'CONFIRMED' AND hold_until < NOW()
        RETURNING id, COALESCE(assigned_spot_id, original_spot_id) AS active_slot
    ),
    slot_released AS (
        UPDATE slots
        SET status = 'AVAILABLE', updated_at = NOW()
        WHERE id IN (SELECT active_slot FROM expired) AND status = 'RESERVED'
        RETURNING id
    )
    SELECT COUNT(*) INTO v_count FROM expired;

    IF v_count > 0 THEN
        PERFORM fn_write_audit_log(
            NULL, 'SYSTEM', 'SYSTEM',
            'RESERVATION', 'RESERVATION_EXPIRED_BATCH',
            'reservations', NULL, NULL, NULL,
            FORMAT('Expired %s reservations', v_count),
            'SYSTEM', 'INFO'
        );
    END IF;

    RETURN v_count;
END;
$$ LANGUAGE plpgsql;

-- [F18] fn_refresh_materialized_views - CONCURRENTLY an toàn nhờ UNIQUE INDEX có sẵn
CREATE OR REPLACE FUNCTION fn_refresh_materialized_views()
RETURNS VOID AS $$
BEGIN
    REFRESH MATERIALIZED VIEW CONCURRENTLY mv_daily_revenue;
    REFRESH MATERIALIZED VIEW CONCURRENTLY mv_slot_occupancy;
END;
$$ LANGUAGE plpgsql;

