-- Gán quyền cho roles
DO $$
DECLARE
    v_admin_role_id   BIGINT;
    v_manager_role_id BIGINT;
    v_staff_role_id   BIGINT;
    v_driver_role_id  BIGINT;
    v_perm_id         BIGINT;
    v_perm_code       TEXT;

    v_admin_perms TEXT[] := ARRAY[
        'AUTH_LOGIN','AUTH_LOGOUT',
        'USER_VIEW','USER_CREATE','USER_UPDATE','USER_DELETE','USER_VERIFY_RESIDENT',
        'FACILITY_VIEW','FACILITY_CONFIG','FACILITY_LOCK_SLOT',
        'PRICING_VIEW','PRICING_CONFIG',
        'SESSION_CHECKIN','SESSION_CHECKOUT','SESSION_VIEW','SESSION_CANCEL',
        'PAYMENT_VIEW','PAYMENT_CONFIRM_MANUAL','PAYMENT_CANCEL','PAYMENT_REFUND',
        'RESERVATION_CREATE','RESERVATION_CANCEL','RESERVATION_MANAGE','RESERVATION_CHANGE_SLOT',
        'LOST_CARD_CREATE','LOST_CARD_APPROVE',
        'INCIDENT_REPORT','INCIDENT_RESOLVE','MISMATCH_APPROVE',
        'SUBSCRIPTION_VIEW','SUBSCRIPTION_MANAGE',
        'REPORT_VIEW','REPORT_EXPORT','AUDIT_VIEW'
    ];
    v_manager_perms TEXT[] := ARRAY[
        'AUTH_LOGIN','AUTH_LOGOUT',
        'USER_VIEW','USER_UPDATE','USER_VERIFY_RESIDENT',
        'FACILITY_VIEW','FACILITY_LOCK_SLOT','PRICING_VIEW',
        'SESSION_CHECKIN','SESSION_CHECKOUT','SESSION_VIEW','SESSION_CANCEL',
        'PAYMENT_VIEW','PAYMENT_CONFIRM_MANUAL','PAYMENT_CANCEL','PAYMENT_REFUND',
        'RESERVATION_CREATE','RESERVATION_CANCEL','RESERVATION_MANAGE','RESERVATION_CHANGE_SLOT',
        'LOST_CARD_CREATE','LOST_CARD_APPROVE',
        'INCIDENT_REPORT','INCIDENT_RESOLVE','MISMATCH_APPROVE',
        'SUBSCRIPTION_VIEW','SUBSCRIPTION_MANAGE',
        'REPORT_VIEW','REPORT_EXPORT','AUDIT_VIEW'
    ];
    v_staff_perms TEXT[] := ARRAY[
        'AUTH_LOGIN','AUTH_LOGOUT','FACILITY_VIEW','PRICING_VIEW',
        'SESSION_CHECKIN','SESSION_CHECKOUT','SESSION_VIEW',
        'PAYMENT_VIEW','PAYMENT_CONFIRM_MANUAL',
        'RESERVATION_MANAGE','RESERVATION_CHANGE_SLOT',
        'LOST_CARD_CREATE','INCIDENT_REPORT','SUBSCRIPTION_VIEW'
    ];
    v_driver_perms TEXT[] := ARRAY[
        'AUTH_LOGIN','AUTH_LOGOUT',
        'RESERVATION_CREATE','RESERVATION_CANCEL',
        'PAYMENT_VIEW','SUBSCRIPTION_VIEW'
    ];
BEGIN
    SELECT id INTO v_admin_role_id   FROM roles WHERE role_name = 'ADMIN';
    SELECT id INTO v_manager_role_id FROM roles WHERE role_name = 'MANAGER';
    SELECT id INTO v_staff_role_id   FROM roles WHERE role_name = 'STAFF';
    SELECT id INTO v_driver_role_id  FROM roles WHERE role_name = 'DRIVER';

    FOREACH v_perm_code IN ARRAY v_admin_perms LOOP
        SELECT id INTO v_perm_id FROM permissions WHERE permission_code = v_perm_code;
        INSERT INTO role_permissions (role_id, permission_id)
        VALUES (v_admin_role_id, v_perm_id) ON CONFLICT DO NOTHING;
    END LOOP;
    FOREACH v_perm_code IN ARRAY v_manager_perms LOOP
        SELECT id INTO v_perm_id FROM permissions WHERE permission_code = v_perm_code;
        INSERT INTO role_permissions (role_id, permission_id)
        VALUES (v_manager_role_id, v_perm_id) ON CONFLICT DO NOTHING;
    END LOOP;
    FOREACH v_perm_code IN ARRAY v_staff_perms LOOP
        SELECT id INTO v_perm_id FROM permissions WHERE permission_code = v_perm_code;
        INSERT INTO role_permissions (role_id, permission_id)
        VALUES (v_staff_role_id, v_perm_id) ON CONFLICT DO NOTHING;
    END LOOP;
    FOREACH v_perm_code IN ARRAY v_driver_perms LOOP
        SELECT id INTO v_perm_id FROM permissions WHERE permission_code = v_perm_code;
        INSERT INTO role_permissions (role_id, permission_id)
        VALUES (v_driver_role_id, v_perm_id) ON CONFLICT DO NOTHING;
    END LOOP;
END $$;

